		private TupleExpr tupleFunctionCall(ObjectNode object, String path) throws TupleExprJsonParseException {
			checkNodeFields(object, path, "uri", "args", "resultVars");
			TupleFunctionCall result = new TupleFunctionCall();
			result.setURI(requiredNonEmptyText(object, "uri", path));
			ArrayNode args = optionalArray(object, "args", path);
			if (args != null) {
				for (int i = 0; i < args.size(); i++) {
					result.addArg(valueExpr(args.get(i), index(child(path, "args"), i)));
				}
			}
			ArrayNode resultVars = requireArray(required(object, "resultVars", path), child(path, "resultVars"),
					"resultVars");
			for (int i = 0; i < resultVars.size(); i++) {
				result.addResultVar(variable(resultVars.get(i), index(child(path, "resultVars"), i)));
			}
			return applyCommon(result, object, path);
		}

