		private CompareOp compareOperator(String value, String path) throws TupleExprJsonParseException {
			for (CompareOp operator : CompareOp.values()) {
				if (operator.name().equalsIgnoreCase(value) || operator.getSymbol().equals(value)) {
					return operator;
				}
			}
			throw error(path, "unknown comparison operator \"" + value + "\"");
		}

